#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define MAX_SERVERS 10
#define MAX_VMS_PER_SERVER 50
#define MAX_TENANTS 100

// VM states in hypervisor
typedef enum {
    VM_STATE_CREATED,
    VM_STATE_RUNNING,
    VM_STATE_PAUSED,
    VM_STATE_STOPPED
} VMState;

// Virtual Machine structure (guest OS abstraction)
typedef struct {
    char vm_id[32];
    char tenant_id[32];
    char host_server_id[32];
    int vCPUs;
    int vRAM_MB;
    int vDisk_GB;
    VMState state;
} VirtualMachine;

// Physical Server structure (host)
typedef struct {
    char server_id[32];
    int total_cpu_cores;
    int total_ram_MB;
    int total_storage_GB;
    int used_cpu_cores;
    int used_ram_MB;
    int used_storage_GB;
    int vm_count;
    VirtualMachine* vms[MAX_VMS_PER_SERVER];
} PhysicalServer;

// Datacenter Resource Pool
typedef struct {
    PhysicalServer servers[MAX_SERVERS];
    int server_count;
    int total_vm_count;
} Datacenter;

// Initialize a physical server
void init_server(PhysicalServer* server, const char* id, int cpu, int ram, int storage) {
    strncpy(server->server_id, id, 31);
    server->total_cpu_cores = cpu;
    server->total_ram_MB = ram;
    server->total_storage_GB = storage;
    server->used_cpu_cores = 0;
    server->used_ram_MB = 0;
    server->used_storage_GB = 0;
    server->vm_count = 0;

    for (int i = 0; i < MAX_VMS_PER_SERVER; i++) {
        server->vms[i] = NULL;
    }
}

// Check if server has enough resources
bool can_allocate_resources(PhysicalServer* server, int cpu, int ram, int storage) {
    return (server->total_cpu_cores - server->used_cpu_cores >= cpu &&
            server->total_ram_MB - server->used_ram_MB >= ram &&
            server->total_storage_GB - server->used_storage_GB >= storage);
}

// Allocate resources to VM (simulates hypervisor partitioning)
bool allocate_vm_on_server(PhysicalServer* server, VirtualMachine* vm) {
    if (!can_allocate_resources(server, vm->vCPUs, vm->vRAM_MB, vm->vDisk_GB)) {
        return false;
    }

    if (server->vm_count >= MAX_VMS_PER_SERVER) {
        return false;
    }

    // Update resource allocation (hypervisor tracks this)
    server->used_cpu_cores += vm->vCPUs;
    server->used_ram_MB += vm->vRAM_MB;
    server->used_storage_GB += vm->vDisk_GB;

    // Add VM to server's VM list
    server->vms[server->vm_count] = vm;
    server->vm_count++;

    return true;
}

// Create and provision a new VM (IaaS service)
VirtualMachine* provision_vm(Datacenter* dc, const char* tenant_id, 
                              int vcpus, int vram_mb, int vdisk_gb) {

    // Allocate VM structure
    VirtualMachine* vm = (VirtualMachine*)malloc(sizeof(VirtualMachine));
    if (!vm) return NULL;

    // Generate VM ID
    sprintf(vm->vm_id, "vm-%s-%d", tenant_id, dc->total_vm_count + 1);
    strncpy(vm->tenant_id, tenant_id, 31);
    vm->vCPUs = vcpus;
    vm->vRAM_MB = vram_mb;
    vm->vDisk_GB = vdisk_gb;
    vm->state = VM_STATE_CREATED;

    // Find server with best fit
    PhysicalServer* best_server = NULL;
    int best_remaining_cpu = __INT_MAX__;

    for (int i = 0; i < dc->server_count; i++) {
        PhysicalServer* server = &dc->servers[i];

        if (can_allocate_resources(server, vcpus, vram_mb, vdisk_gb)) {
            int remaining = server->total_cpu_cores - server->used_cpu_cores;
            if (remaining < best_remaining_cpu) {
                best_remaining_cpu = remaining;
                best_server = server;
            }
        }
    }

    if (best_server == NULL) {
        printf("[Hypervisor] ERROR: No server with sufficient resources!\n");
        free(vm);
        return NULL;
    }

    // Allocate VM on selected server
    if (allocate_vm_on_server(best_server, vm)) {
        strncpy(vm->host_server_id, best_server->server_id, 31);
        vm->state = VM_STATE_RUNNING;
        dc->total_vm_count++;

        printf("[Hypervisor] SUCCESS: VM %s provisioned on %s\n", 
               vm->vm_id, best_server->server_id);
        printf("    Allocated: %d vCPUs, %d MB vRAM, %d GB vDisk\n", 
               vcpus, vram_mb, vdisk_gb);

        return vm;
    }

    free(vm);
    return NULL;
}

// Terminate and deallocate VM
bool terminate_vm(Datacenter* dc, const char* vm_id) {
    for (int i = 0; i < dc->server_count; i++) {
        PhysicalServer* server = &dc->servers[i];

        for (int j = 0; j < server->vm_count; j++) {
            if (server->vms[j] && strcmp(server->vms[j]->vm_id, vm_id) == 0) {
                // Release resources back to pool
                server->used_cpu_cores -= server->vms[j]->vCPUs;
                server->used_ram_MB -= server->vms[j]->vRAM_MB;
                server->used_storage_GB -= server->vms[j]->vDisk_GB;

                // Free VM memory
                free(server->vms[j]);
                server->vms[j] = NULL;

                // Compact VM list (simple approach)
                for (int k = j; k < server->vm_count - 1; k++) {
                    server->vms[k] = server->vms[k + 1];
                }
                server->vm_count--;
                dc->total_vm_count--;

                printf("[Hypervisor] VM %s terminated, resources returned to pool\n", vm_id);
                return true;
            }
        }
    }
    return false;
}

// Print datacenter resource utilization
void print_datacenter_status(Datacenter* dc) {
    printf("\n========== DATACENTER RESOURCE POOL STATUS ==========\n");

    int total_cpu = 0, used_cpu = 0;
    int total_ram = 0, used_ram = 0;

    for (int i = 0; i < dc->server_count; i++) {
        PhysicalServer* s = &dc->servers[i];
        total_cpu += s->total_cpu_cores;
        used_cpu += s->used_cpu_cores;
        total_ram += s->total_ram_MB;
        used_ram += s->used_ram_MB;

        printf("Server %s: %d VMs | CPU: %d/%d | RAM: %d/%d MB | Storage: %d/%d GB\n",
               s->server_id, s->vm_count,
               s->used_cpu_cores, s->total_cpu_cores,
               s->used_ram_MB, s->total_ram_MB,
               s->used_storage_GB, s->total_storage_GB);
    }

    printf("--------------------------------------------------------\n");
    printf("Total VMs: %d | Overall CPU: %d/%d (%.1f%%) | RAM: %d/%d MB (%.1f%%)\n",
           dc->total_vm_count,
           used_cpu, total_cpu, (float)used_cpu/total_cpu*100,
           used_ram, total_ram, (float)used_ram/total_ram*100);
    printf("========================================================\n\n");
}

int main() {
    // Initialize datacenter with physical servers (Physical Layer)
    Datacenter datacenter;
    datacenter.server_count = 0;
    datacenter.total_vm_count = 0;

    // Add physical servers to the virtualized datacenter
    init_server(&datacenter.servers[datacenter.server_count++], 
                "PHYS-HOST-01", 64, 262144, 5000);  // 64 cores, 256GB RAM, 5TB
    init_server(&datacenter.servers[datacenter.server_count++], 
                "PHYS-HOST-02", 64, 262144, 5000);
    init_server(&datacenter.servers[datacenter.server_count++], 
                "PHYS-HOST-03", 128, 524288, 10000); // 128 cores, 512GB RAM, 10TB

    printf("=== Cloud Platform Architecture Simulation ===\n");
    printf("Virtualized Datacenter initialized with %d physical servers\n\n", 
           datacenter.server_count);

    // Simulate IaaS: Provision VMs for different tenants
    printf("--- IaaS: Provisioning VMs for Multiple Tenants ---\n");

    provision_vm(&datacenter, "tenant-ecommerce", 4, 16384, 500);   // 4 vCPU, 16GB, 500GB
    provision_vm(&datacenter, "tenant-analytics", 16, 65536, 2000); // 16 vCPU, 64GB, 2TB
    provision_vm(&datacenter, "tenant-webapp", 2, 8192, 250);      // 2 vCPU, 8GB, 250GB
    provision_vm(&datacenter, "tenant-ml", 32, 131072, 4000);      // 32 vCPU, 128GB, 4TB

    print_datacenter_status(&datacenter);

    // Simulate PaaS: Platform service request (higher-level abstraction)
    printf("--- PaaS: Platform Service Request ---\n");
    printf("[Orchestrator] Request: Managed Kubernetes Cluster\n");
    printf("[Orchestrator] Auto-provisioning 3 VMs for k8s cluster...\n");
    provision_vm(&datacenter, "tenant-k8s", 8, 32768, 1000);
    provision_vm(&datacenter, "tenant-k8s", 8, 32768, 1000);
    provision_vm(&datacenter, "tenant-k8s", 8, 32768, 1000);

    print_datacenter_status(&datacenter);

    // Terminate a VM and observe resource return to pool
    printf("--- Terminating Tenant VM ---\n");
    terminate_vm(&datacenter, "vm-tenant-analytics-2");

    print_datacenter_status(&datacenter);

    return 0;
}
